1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life", () => {
5	  it("should return empty grid for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should return empty grid for single isolated cell", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should return empty grid for two isolated cells", () => {
12	    expect(nextGeneration([[0, 0], [2, 2]])).toEqual([]);
13	  });
14	  it("should evolve three in a row to vertical blinker", () => {
15	    expect(nextGeneration([[0, 1], [1, 1], [2, 1]])).toEqual([[1, 0], [1, 1], [1, 2]]);
16	  });
17	  it("should keep two by two block stable", () => {
18	    expect(nextGeneration([[0, 0], [0, 1], [1, 0], [1, 1]])).toEqual([[0, 0], [0, 1], [1, 0], [1, 1]]);
19	  });
20	  it("should create live cell from dead cell with exactly 3 neighbors", () => {
21	    expect(nextGeneration([[0, 0], [0, 1], [1, 0]])).toEqual([[0, 0], [0, 1], [1, 0], [1, 1]]);
22	  });
23	  it("should kill live cell with 4 neighbors (overpopulation)", () => {
24	    // Cell [1,1] has 4 neighbors: [1,0], [0,1], [2,1], [1,2]
25	    // It should die due to overpopulation
26	    expect(nextGeneration([[1, 0], [0, 1], [1, 1], [2, 1], [1, 2]])).toEqual([]);
27	  });
28	});
