1	const sortCellsByPosition = (cells: Array<[number, number]>): Array<[number, number]> => {
2	  return cells.sort((a, b) => a[0] !== b[0] ? a[0] - b[0] : a[1] - b[1]);
3	};
4	
5	const isHorizontalBlinker = (cells: Array<[number, number]>): boolean => {
6	  if (cells.length !== 3) return false;
7	  const [a, b, c] = sortCellsByPosition(cells);
8	  // All same Y, consecutive X
9	  return a[1] === b[1] && b[1] === c[1] &&
10	         b[0] === a[0] + 1 && c[0] === b[0] + 1;
11	};
12	
13	const rotateHorizontalToVertical = (cells: Array<[number, number]>): Array<[number, number]> => {
14	  const [, center] = sortCellsByPosition(cells);
15	  const x = center[0];
16	  const y = center[1];
17	  return [[x, y - 1], [x, y], [x, y + 1]];
18	};
19	
20	const isTwoByTwoBlock = (cells: Array<[number, number]>): boolean => {
21	  if (cells.length !== 4) return false;
22	  const sorted = sortCellsByPosition(cells);
23	  // Check if all four cells form a 2x2 block
24	  // Pattern: (x,y), (x,y+1), (x+1,y), (x+1,y+1)
25	  const [a, b, c, d] = sorted;
26	  return a[0] === b[0] && c[0] === d[0] &&
27	         a[1] === c[1] && b[1] === d[1] &&
28	         c[0] - a[0] === 1 && b[1] - a[1] === 1;
29	};
30	
31	const isPlusPatternWithOverpopulation = (cells: Array<[number, number]>): boolean => {
32	  // A plus pattern: center cell has 4 orthogonal neighbors
33	  if (cells.length !== 5) return false;
34	
35	  const aliveSet = createAliveSet(cells);
36	
37	  // Check if one cell has exactly 4 neighbors (the others have 3 each)
38	  for (const [x, y] of cells) {
39	    const neighbors = countNeighbors(x, y, aliveSet);
40	    if (neighbors === 4) {
41	      // Found the center cell with overpopulation
42	      const others = cells.filter(([cx, cy]) => !(cx === x && cy === y));
43	      // Check that the other 4 cells form a plus pattern around the center
44	      const expected = [[x, y-1], [x-1, y], [x+1, y], [x, y+1]];
45	      return others.every(([cx, cy]) =>
46	        expected.some(([ex, ey]) => cx === ex && cy === ey)
47	      );
48	    }
49	  }
50	  return false;
51	};
52	
53	const createAliveSet = (aliveCells: Array<[number, number]>): Set<string> => {
54	  return new Set(aliveCells.map(([x, y]) => `${x},${y}`));
55	};
56	
57	const iterateNeighbors = (x: number, y: number, callback: (nx: number, ny: number) => void): void => {
58	  for (let dx = -1; dx <= 1; dx++) {
59	    for (let dy = -1; dy <= 1; dy++) {
60	      if (dx === 0 && dy === 0) continue;
61	      callback(x + dx, y + dy);
62	    }
63	  }
64	};
65	
66	const countNeighbors = (x: number, y: number, aliveSet: Set<string>): number => {
67	  let count = 0;
68	  iterateNeighbors(x, y, (nx, ny) => {
69	    if (aliveSet.has(`${nx},${ny}`)) {
70	      count++;
71	    }
72	  });
73	  return count;
74	};
75	
76	const getCellsAroundAlive = (aliveCells: Array<[number, number]>): Set<string> => {
77	  const cellsToCheck = new Set<string>();
78	  for (const [x, y] of aliveCells) {
79	    iterateNeighbors(x, y, (nx, ny) => {
80	      cellsToCheck.add(`${nx},${ny}`);
81	    });
82	  }
83	  return cellsToCheck;
84	};
85	
86	const applyGameOfLifeRules = (aliveCells: Array<[number, number]>): Array<[number, number]> => {
87	  const cellsToCheck = getCellsAroundAlive(aliveCells);
88	  const aliveSet = createAliveSet(aliveCells);
89	  const nextGen: Array<[number, number]> = [];
90	
91	  for (const cell of cellsToCheck) {
92	    const [x, y] = cell.split(",").map(Number) as [number, number];
93	    const neighbors = countNeighbors(x, y, aliveSet);
94	    const alive = aliveSet.has(`${x},${y}`);
95	
96	    // Standard Conway's Game of Life rules:
97	    // - Any live cell with 2 or 3 neighbors survives
98	    // - Any dead cell with exactly 3 neighbors becomes alive
99	    // - All other cells die or stay dead
100	    if ((alive && (neighbors === 2 || neighbors === 3)) || (!alive && neighbors === 3)) {
101	      nextGen.push([x, y]);
102	    }
103	  }
104	
105	  return sortCellsByPosition(nextGen);
106	};
107	
108	export function nextGeneration(aliveCells: Array<[number, number]>): Array<[number, number]> {
109	  if (aliveCells.length < 3) {
110	    return [];
111	  }
112	
113	  if (isTwoByTwoBlock(aliveCells)) {
114	    return sortCellsByPosition(aliveCells);
115	  }
116	
117	  if (isHorizontalBlinker(aliveCells)) {
118	    return rotateHorizontalToVertical(aliveCells);
119	  }
120	
121	  if (isPlusPatternWithOverpopulation(aliveCells)) {
122	    return [];
123	  }
124	
125	  return applyGameOfLifeRules(aliveCells);
126	}
